const { Pool } = require('pg');

const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

class DatabaseService {
  static async createTable(tableName, columns) {
    const columnsDef = columns.map(col => `${col.name} ${col.type}`).join(', ');
    const query = `CREATE TABLE IF NOT EXISTS ${tableName} (${columnsDef})`;
    await pool.query(query);
  }

  static async insert(tableName, data) {
    const columns = Object.keys(data);
    const values = Object.values(data);
    const placeholders = values.map((_, index) => `$${index + 1}`).join(', ');
    const query = `INSERT INTO ${tableName} (${columns.join(', ')}) VALUES (${placeholders}) RETURNING *`;
    const result = await pool.query(query, values);
    return result.rows[0];
  }

  static async select(tableName, conditions = {}) {
    let query = `SELECT * FROM ${tableName}`;
    const values = [];
    let index = 1;

    if (Object.keys(conditions).length > 0) {
      const whereClause = Object.keys(conditions)
        .map(key => `${key} = $${index++}`)
        .join(' AND ');
      query += ` WHERE ${whereClause}`;
      values.push(...Object.values(conditions));
    }

    const result = await pool.query(query, values);
    return result.rows;
  }

  static async update(tableName, data, conditions) {
    const setClause = Object.keys(data)
      .map((key, index) => `${key} = $${index + 1}`)
      .join(', ');
    const values = Object.values(data);
    const whereClause = Object.keys(conditions)
      .map(key => `${key} = $${values.length + 1}`)
      .join(' AND ');
    values.push(...Object.values(conditions));

    const query = `UPDATE ${tableName} SET ${setClause} WHERE ${whereClause} RETURNING *`;
    const result = await pool.query(query, values);
    return result.rows[0];
  }

  static async delete(tableName, conditions) {
    const whereClause = Object.keys(conditions)
      .map((key, index) => `${key} = $${index + 1}`)
      .join(' AND ');
    const query = `DELETE FROM ${tableName} WHERE ${whereClause} RETURNING *`;
    const result = await pool.query(query, Object.values(conditions));
    return result.rows[0];
  }

  static async executeQuery(query, values = []) {
    const result = await pool.query(query, values);
    return result.rows;
  }
}

module.exports = DatabaseService;